var maxBottlesDrunk = function(numBottles, numExchange) {
    let total = 0, full = numBottles, empty = 0, rate = numExchange;
    while (full > 0) {
        total += full;
        empty += full;
        full = 0;
        while (empty >= rate) {
            empty -= rate;
            full++;
            rate++;
        }
    }
    return total;
};
